  $fulfillmentType: TimeslotFulfillmentType!
  $pickupStoreId: String!
  $deliveryAddress: FulfillmentAddressInput
  $ignoreCartConflicts: Boolean!
  $storeId: Int!
  $userIsLoggedIn: Boolean!
) {
  reserveTimeslotV3(
    fulfillmentType: $fulfillmentType
    fulfillmentPickup: { pickupStoreId: $pickupStoreId }
    fulfillmentDelivery: { deliveryAddress: $deliveryAddress }
    timeslot: { id: $id, date: $date }
    ignoreCartConflicts: $ignoreCartConflicts
