query typeaheadContent($term: String, $searchMode: SearchMode) {
  typeaheadContent(term: $term, searchMode: $searchMode) {
    verticalStack {
      ... on TypeaheadTypingSuggestedSearches {
        terms
      }
      ... on TypeaheadRecentSearches {
        recentSearchTerms
      }
      ... on TypeaheadTrendingSearches {
        trendingSearches
      }
      ... on TypeaheadTrendingCategories {
        trendingCategories {
          categoryName
          categoryUrl
        }
      }
      ... on TypeaheadShortcuts {
        sectionTitle
        typeaheadShortcuts {
          name
          id
          shortcutImageUrl
          shortcutText
          shortcutCardDestinationUrl
          shortcutImageAltText
        }
      }
    }
  }
}

query ProductGroupDetails(
  $paging: PagingArgs!
  $id: String!
  $storeId: Int!
  $shoppingContext: ShoppingContext!
  $filter: String
  $sortBy: SearchSortBy
  $sortDirection: SearchSortDirection
) {
  productGroupDetails(
    paging: $paging
    id: $id
    storeId: $storeId
    shoppingContext: $shoppingContext
    filter: $filter
    sortBy: $sortBy
    sortDirection: $sortDirection
  ) {
    records {
      ...ProductSearchFragment
    }
    cursorList
    previousCursor
    nextCursor
    total
    hasMoreRecords
    filters {
      ...ProductSearchFiltersFragment
    }
    sortValues {
      displayName
      sortBy
      sortDirection
      selected
      isDefault
    }
  }
}

query CategoryBrowsePage(
  $params: CategoryBrowsePageParams!
  $storeId: Int!
  $storeIdString: String!
  $categoryId: String!
  $searchContextToken: String
  $searchPageLayout: SearchPageLayout!
  $shoppingContext: ShoppingContext!
  $userIsLoggedIn: Boolean = false
) {
  categoryBrowsePage(
    params: $params
    searchContextToken: $searchContextToken
    searchPageLayout: $searchPageLayout
  ) {
    ... on SearchPage {
      layout {
        ...LayoutFragment
        ... on VerticalStackLayout {
          visualComponents {
            ... on HrmBannerV1 {
              ...CategoryBillboardBannerFragment
            }
          }
        }
      }
      redirectToUrl
      categoryBreadCrumbs {
        ...CategoryBreadcrumbsFragment
      }
      sponsoredHeaderBanners {
        ...SponsoredHeaderBannerFragment
      }
    }
    ... on SearchPageError {
      code
      message
    }
  }
}

