query productSearchItems(
  $params: SearchPageParamsV2!
  $searchMode: SearchMode
  $searchContextToken: String
  $searchPageLayout: SearchPageLayout!
  $amount: Float = 0.00
  $includeUnitPriceDiff: Boolean! = false
  $storeId: Int!
  $shoppingContext: ShoppingContext!
  $userIsLoggedIn: Boolean = false
) {
  productSearchItems(
    params: $params
    searchMode: $searchMode
    searchContextToken: $searchContextToken
    searchPageLayout: $searchPageLayout
  ) {
    ... on ProductSearchItemsResult {
      redirectToUrl
      searchGrid {
        ...SearchGridV2Fragment
        items {
          ... on Product @skip(if: $includeUnitPriceDiff) {
            ...ProductSearchFragment
          }
          ... on Product @include(if: $includeUnitPriceDiff) {
            ...ProductSearchWithPriceDiffFragment
          }
        }
      }
      sponsoredHeaderBanners {
        ...SponsoredHeaderBannerFragment
      }
    }
    ... on SearchPageError {
      code
